import { useState } from "react";
import { T } from "../data/config";
import { Btn, Card, Tag } from "../components/UI";

export default function JobsPage({ jobs, nav }) {
  const [q, setQ]       = useState("");
  const [dept, setDept] = useState("All");
  const [loc, setLoc]   = useState("All");

  const depts    = ["All", ...new Set(jobs.map(j => j.dept))];
  const locs     = ["All", ...new Set(jobs.flatMap(j => j.loc.split(",").map(l => l.trim())))];
  const filtered = jobs.filter(j => {
    const s = q.toLowerCase();
    return (
      (j.title.toLowerCase().includes(s) || j.dept.toLowerCase().includes(s)) &&
      (dept === "All" || j.dept === dept) &&
      (loc  === "All" || j.loc.includes(loc))
    );
  });

  return (
    <div className="page">
      {/* Header */}
      <div className="hero-grad" style={{ padding: "56px 28px 48px", textAlign: "center", position: "relative", overflow: "hidden" }}>
        <div className="dot-bg" style={{ position: "absolute", inset: 0, opacity: .22 }} />
        <div style={{ position: "relative", zIndex: 1 }}>
          <Tag color="rgba(255,255,255,.9)" sx={{ background: "rgba(255,255,255,.15)", border: "1px solid rgba(255,255,255,.25)", marginBottom: 14 }}>CURRENT OPENINGS</Tag>
          <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 40, fontWeight: 800, color: "#fff", margin: "0 0 10px" }}>Find Your Next Role</h1>
          <p style={{ color: "rgba(255,255,255,.72)", marginBottom: 30 }}>Curated opportunities across Healthcare, IT & BFSI</p>
          <div style={{ maxWidth: 540, margin: "0 auto", position: "relative" }}>
            <span style={{ position: "absolute", left: 16, top: "50%", transform: "translateY(-50%)", fontSize: 15, pointerEvents: "none" }}>🔍</span>
            <input value={q} onChange={e => setQ(e.target.value)} placeholder="Search by title or department…"
              style={{ width: "100%", boxSizing: "border-box", padding: "14px 16px 14px 46px", borderRadius: 12, border: "none", fontSize: 15, fontFamily: "inherit", outline: "none", boxShadow: "0 8px 32px rgba(0,0,0,.14)" }} />
          </div>
        </div>
      </div>

      {/* Filters */}
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "36px 28px" }}>
        <div style={{ display: "flex", gap: 14, flexWrap: "wrap", marginBottom: 26, alignItems: "flex-end" }}>
          {[["Department", depts, dept, setDept], ["Location", locs, loc, setLoc]].map(([lbl, opts, val, setter]) => (
            <div key={lbl}>
              <div style={{ fontSize: 11, fontWeight: 700, color: T.greyMd, marginBottom: 5, letterSpacing: 1, textTransform: "uppercase" }}>{lbl}</div>
              <select value={val} onChange={e => setter(e.target.value)}
                style={{ border: `1.5px solid ${T.border}`, borderRadius: 8, padding: "9px 14px", fontSize: 13, background: T.white, fontFamily: "inherit", cursor: "pointer" }}>
                {opts.map(o => <option key={o}>{o}</option>)}
              </select>
            </div>
          ))}
          <div style={{ marginLeft: "auto", alignSelf: "center", fontSize: 14, fontWeight: 600, color: T.greyMd }}>
            {filtered.length} position{filtered.length !== 1 ? "s" : ""}
          </div>
        </div>

        {!filtered.length ? (
          <div style={{ textAlign: "center", padding: 80 }}>
            <div style={{ fontSize: 52, marginBottom: 14 }}>🔎</div>
            <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 6 }}>No results found</div>
            <div style={{ color: T.greyLt }}>Try adjusting your search or filters</div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {filtered.map((job, i) => (
              <Card key={job.id} cls="hover-card fade-up" sx={{ padding: "22px 26px", cursor: "pointer", animationDelay: `${i * .055}s` }} onClick={() => nav("job", job.id)}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 16, flexWrap: "wrap" }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap", marginBottom: 8 }}>
                      <span style={{ fontWeight: 700, fontSize: 18, color: T.dark, fontFamily: "'Playfair Display',serif" }}>{job.title}</span>
                      {job.urgent && <Tag color="#D97706">🔥 URGENT</Tag>}
                      {job.cert   && <Tag color={T.purple}>CERT. REQ.</Tag>}
                    </div>
                    <div style={{ fontSize: 13, color: T.greyMd, marginBottom: 12 }}>
                      {job.dept} &nbsp;·&nbsp; 📍 {job.loc} &nbsp;·&nbsp; 💼 {job.exp} &nbsp;·&nbsp; {job.salary}
                    </div>
                    <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                      <Tag>{job.mode}</Tag>
                      <Tag color={T.blue}>{job.interview} Interview</Tag>
                      <Tag color={T.green}>{job.type}</Tag>
                    </div>
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 8, alignItems: "flex-end" }}>
                    <Btn sz="sm">View Details →</Btn>
                    <span style={{ fontSize: 11, color: T.greyLt }}>Posted {job.posted}</span>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
